对k循环和j循环进行分块，以改善数据局部性。将k循环分成大小为BK的块，j循环分成大小为BJ的块。

for (int kk = 0; kk < _PB_M; kk += BK) {
  for (int jj = 0; jj <= i; jj += BJ) {
    int k_end = min(kk + BK, _PB_M);
    int j_end = min(jj + BJ, i+1);
    for (int k = kk; k < k_end; k++) {
      DATA_TYPE a_ik = alpha * A[i][k];
      for (int j = jj; j < j_end; j++) {
        C[i][j] += a_ik * A[j][k];
      }
    }
  }
}

在内层循环中重用A[i][k]值，减少内存访问。对j循环进行部分展开。

for (k = 0; k < _PB_M; k++) {
  DATA_TYPE a_ik = alpha * A[i][k];
  for (j = 0; j <= i-3; j += 4) {
    C[i][j]   += a_ik * A[j][k];
    C[i][j+1] += a_ik * A[j+1][k];
    C[i][j+2] += a_ik * A[j+2][k];
    C[i][j+3] += a_ik * A[j+3][k];
  }
  // 处理剩余迭代
  for (; j <= i; j++) {
    C[i][j] += a_ik * A[j][k];
  }
}

在计算前对A矩阵进行转置，使A[j][k]的访问变为连续的。

// 预处理阶段
DATA_TYPE POLYBENCH_2D(AT,M,N,m,n);
for (int i = 0; i < n; i++)
  for (int k = 0; k < m; k++)
    AT[k][i] = A[i][k];

// 计算阶段
for (i = 0; i < _PB_N; i++) {
  for (j = 0; j <= i; j++)
    C[i][j] *= beta;
  for (k = 0; k < _PB_M; k++) {
    DATA_TYPE a_ik = alpha * A[i][k];
    for (j = 0; j <= i; j++) {
      C[i][j] += a_ik * AT[k][j];  // 连续访问
    }
  }
}
